import{_ as o,o as e,c as t,a2 as r}from"./chunks/framework.BWuWLRhz.js";const c=JSON.parse('{"title":"ADR-0001: 日记原语 — 事件流与状态层分离","description":"","frontmatter":{},"headers":[],"relativePath":"adr/0001-diary-store.md","filePath":"adr/0001-diary-store.md","lastUpdated":1784633569000}'),i={name:"adr/0001-diary-store.md"};function n(l,a,s,d,u,h){return e(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="adr-0001-日记原语-—-事件流与状态层分离" tabindex="-1">ADR-0001: 日记原语 — 事件流与状态层分离 <a class="header-anchor" href="#adr-0001-日记原语-—-事件流与状态层分离" aria-label="Permalink to &quot;ADR-0001: 日记原语 — 事件流与状态层分离&quot;">​</a></h1><ul><li><strong>状态</strong>：Proposed（2026-07-21，随 PR 评审定稿）</li><li><strong>日期</strong>：2026-07-21</li><li><strong>关联</strong>：<a href="./0002-time-range-retrieval.html">ADR-0002</a>（时间检索建立在本原语上）、<a href="https://github.com/XnneHangLab/XnneHangLab/blob/dev/docs/adr/0001-llm-mode-memory.md" target="_blank" rel="noreferrer">XnneHangLab ADR-0001</a>（创始设计与硬约束来源）</li></ul><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>wikimem 目前只有一种存储原语：category/item 的 <strong>wiki（状态层）</strong>——内容是主轴，条目可改写。<code>ts</code> 随条目存储，但从未参与检索。</p><p>陪伴/桌宠场景需要回答&quot;前天晚上我吃了什么&quot;这类问题，这要求一种<strong>以时间为主轴的情景记忆（事件流）</strong>，当前缺失——<a href="./0002-time-range-retrieval.html">ADR-0002</a> 的时间门控没有可以门的对象。</p><p>上游两个反面教训：</p><ul><li><strong>MoeChat</strong>：LTM（按天日记）与 CoreMemory（核心事实）用&quot;重要/永久程度&quot;划界。重要性是连续的、会变的，切不出干净边界，两个存储的职责长期模糊。</li><li><strong>memU（早期）</strong>：六种 memory type，每种 type 各跑一遍 LLM，memorize 过重。</li></ul><p>另外，情绪需要归处：只有事实、没有情景，角色就没有灵魂。但&quot;情绪&quot;混进状态层会加剧边界模糊。</p><h2 id="决策" tabindex="-1">决策 <a class="header-anchor" href="#决策" aria-label="Permalink to &quot;决策&quot;">​</a></h2><h3 id="_1-新增第二存储原语-diary-日记-事件流" tabindex="-1">1. 新增第二存储原语：diary（日记，事件流） <a class="header-anchor" href="#_1-新增第二存储原语-diary-日记-事件流" aria-label="Permalink to &quot;1. 新增第二存储原语：diary（日记，事件流）&quot;">​</a></h3><p>与现有 wiki（状态层）并列：</p><ul><li><strong>按天一个 markdown 文件</strong>：<code>diary/YYYY-MM-DD.md</code>，每条 <code>## HH:MM</code> 一个条目，正文后接现有的 HTML 注释 metadata（复用 <code>owner / source_conv / ts</code> 格式）。</li><li><strong>append-only</strong>：框架只提供追加与读取 API，不提供改写既有条目的 API（人当然可以直接改文件——文件即真相，硬约束 3 不变）。</li><li><strong>条目内容是宿主 LLM 写的生动短段落</strong>——场景、情绪、事实在一起。框架不生成内容、不做质量判断（写什么、何时写、什么文风，是宿主的 memorize 策略，见 XnneHangLab ADR-0004）。</li><li>条目内容<strong>可含 wiki-links</strong>，与状态层互链。</li><li><code>journal.jsonl</code> 照记 diary 写入，与 wiki 写入同一套操作日志。</li></ul><h3 id="_2-边界规则-一条就够" tabindex="-1">2. 边界规则（一条就够） <a class="header-anchor" href="#_2-边界规则-一条就够" aria-label="Permalink to &quot;2. 边界规则（一条就够）&quot;">​</a></h3><blockquote><p><strong>&quot;发生过的事&quot;进日记，&quot;现在为真的事&quot;进 wiki。</strong></p></blockquote><p>判据是离散的：一条记忆有没有&quot;它发生在何时&quot;这个属性。同一件事可以两侧成对出现——日记记事件（&quot;7 月 21 日，他说他换了工作，语气很兴奋&quot;），wiki 的 <code>work</code> 条目被更新（状态），互不打架。</p><h3 id="_3-不引入-type-分类学" tabindex="-1">3. 不引入 type 分类学 <a class="header-anchor" href="#_3-不引入-type-分类学" aria-label="Permalink to &quot;3. 不引入 type 分类学&quot;">​</a></h3><p>memU 的六种 memory type 属于<strong>状态层的内容策略</strong>，归宿主的 extraction prompt 管（wikimem 的 category 本来就是自由的）。框架只认两种原语：diary 和 wiki。</p><h3 id="_4-当下的情绪状态不进框架" tabindex="-1">4. 当下的情绪状态不进框架 <a class="header-anchor" href="#_4-当下的情绪状态不进框架" aria-label="Permalink to &quot;4. 当下的情绪状态不进框架&quot;">​</a></h3><p>效价/唤醒度这类每轮变化的 runtime 状态（参照 MoeChat 的 emotion_state）不是记忆、不被检索，留在应用运行时。<strong>事件中的情绪</strong>以日记文本的形式进入记忆——&quot;状态即时，情绪入事&quot;。</p><h3 id="_5-文件名即时间索引" tabindex="-1">5. 文件名即时间索引 <a class="header-anchor" href="#_5-文件名即时间索引" aria-label="Permalink to &quot;5. 文件名即时间索引&quot;">​</a></h3><p>日期范围 → 文件集合，O(天数)，零索引结构、零依赖。这是 <a href="./0002-time-range-retrieval.html">ADR-0002</a> 时间门控的地基；MoeChat 用按天 jsonl 验证过这条路，我们只是把载体换成符合硬约束 3 的 markdown。</p><h2 id="理由" tabindex="-1">理由 <a class="header-anchor" href="#理由" aria-label="Permalink to &quot;理由&quot;">​</a></h2><ul><li>&quot;事件 vs 状态&quot;的切分是离散判据，修复了&quot;重要程度&quot;连续谱带来的边界模糊。</li><li>&quot;jsonl 事实碎片 vs 生动 markdown 日记&quot;不二选一：<strong>灵魂在日记，检索精度在 wiki</strong>，两层各司其职。</li><li>按天 markdown 同时满足：人可读可编辑（硬约束 3）、文件名可当时间索引、Obsidian/任意编辑器即免费浏览器。</li></ul><h2 id="后果" tabindex="-1">后果 <a class="header-anchor" href="#后果" aria-label="Permalink to &quot;后果&quot;">​</a></h2><p><strong>正面</strong></p><ul><li>时间检索有了对象（ADR-0002 得以成立）。</li><li>情绪有了归处，且不污染状态层。</li><li>memorize 不加重：宿主单次抽取调用可同时产出 wiki 条目与日记段落（结构化输出一次带回，见 XnneHangLab ADR-0004），仍满足&quot;至多 1 次 LLM 调用&quot;。</li></ul><p><strong>负面 / 代价</strong></p><ul><li>存储 API 面积扩大（Diary 的追加/按日读取/按窗口列举；挂在 <code>MemoryStore</code> 还是独立类，实现期定）。</li><li>日记条目的检索粒度（整条 vs 段落）、同分钟多条目的 heading 去重、wiki-link 能否指向日记条目——实现期需要敲定的开放问题，不在本 ADR 展开。</li><li>BM25 需要覆盖日记文件：窗口内即时构建（天级文件量可忽略，见 ADR-0002）。</li></ul><p><strong>实施</strong></p><p>建议作为下一个里程碑（M5）拆 issue：Diary 存储 API → ADR-0002 的窗口检索 → 宿主插件接入。</p>',30)])])}const p=o(i,[["render",n]]);export{c as __pageData,p as default};
